var chunkSvc *chunkService.Service
var userSvc = userService.NewService()

// 配置常量（应从配置读取，这里使用默认值）
const (
	defaultBaseURL = "http://localhost:12345"
)

func getChunkService() *chunkService.Service {
	if chunkSvc == nil {
		chunkSvc = chunkService.NewService()
	}
	return chunkSvc
}

func getStorageService() storage.StorageInterface {
	return storage.NewConfiguredStorage(conf.GetGlobalConfig(), defaultBaseURL)
}

func getShareService() *shareService.Service {
	baseURL := defaultBaseURL
	if cfg := conf.GetGlobalConfig(); cfg != nil && cfg.Server.BaseURL != "" {
		baseURL = cfg.Server.BaseURL
	}

	shareSvc := shareService.NewService(baseURL, getStorageService())
	shareSvc.SetUserService(userSvc)
	return shareSvc
}

// ChunkUploadInit .
// @router /chunk/upload/init/ [POST]
func ChunkUploadInit(ctx context.Context, c *app.RequestContext) {
	var err error
	var req chunkmodel.ChunkUploadInitReq
	err = c.BindAndValidate(&req)
	if err != nil {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": err.Error(),
		})
		return
	}

	// 参数验证
	if req.FileName == "" {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "文件名不能为空",
		})
		return
	}
	if req.FileSize <= 0 {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "文件大小必须大于0",
		})
		return
	}
	if req.ChunkSize <= 0 {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "分片大小必须大于0",
		})
		return
	}

	// 生成上传ID
	uploadID := req.FileHash
	if uploadID == "" {
		uploadID = uuid.New().String()
	}

	// 检查快速上传：如果文件已存在，直接返回分享代码
	if req.FileHash != "" {
		shareCode, err := getChunkService().CheckQuickUpload(ctx, req.FileHash, req.FileSize)
		if err == nil && shareCode != "" {
			resp := &chunkmodel.ChunkUploadInitResp{
				Code:    200,
				Message: "文件已存在，快速上传成功",
				Data: &chunkmodel.ChunkUploadInitData{
					UploadId:      uploadID,
					ChunkSize:     fmt.Sprintf("%d", req.ChunkSize),
					TotalChunks:   fmt.Sprintf("%d", req.TotalChunks),
					IsQuickUpload: true,
					ShareCode:     shareCode,
				},
			}
			c.JSON(consts.StatusOK, resp)
			return
		}
	}

	// 初始化上传
	initReq := &chunkService.InitiateUploadReq{
		UploadID:    uploadID,
		FileName:    req.FileName,
		TotalChunks: int(req.TotalChunks),
		FileSize:    req.FileSize,
		ChunkSize:   int(req.ChunkSize),
	}

	result, err := getChunkService().InitiateUpload(ctx, initReq)
	if err != nil {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": "初始化上传失败: " + err.Error(),
		})
		return
	}

	// 检查存储是否支持直传
	storageService := getStorageService()
	respData := map[string]interface{}{
		"upload_id":       result.UploadID,
		"chunk_size":      fmt.Sprintf("%d", result.ChunkSize),
		"total_chunks":    fmt.Sprintf("%d", result.TotalChunks),
		"is_quick_upload": false,
		"direct_upload":   false,
	}

	if directUploader, ok := storageService.(storage.DirectUploader); ok && directUploader.SupportsDirectUpload() {
		// 生成文件存储路径
		now := time.Now()
		fileExt := filepath.Ext(req.FileName)
		uuidFileName := uuid.New().String() + fileExt
		objectKey := filepath.Join("uploads", now.Format("2006"), now.Format("01"), now.Format("02"), uuidFileName)
		objectKey = filepath.ToSlash(objectKey) // 统一使用 / 分隔符

		// 初始化平台侧分片上传
		platformUploadID, initErr := directUploader.InitiateMultipartUpload(ctx, objectKey)
		if initErr != nil {
			c.JSON(consts.StatusInternalServerError, map[string]interface{}{
				"code":    500,
				"message": "初始化直传失败: " + initErr.Error(),
			})
			return
		}

		respData["direct_upload"] = true
		respData["upload_mode"] = directUploader.DirectUploadMode()
		respData["platform_upload_id"] = platformUploadID
		respData["object_key"] = objectKey

		// presigned 模式：批量生成预签名 URL
		if directUploader.DirectUploadMode() == storage.DirectUploadModePresigned {
			presignedURLs, urlErr := directUploader.GenerateUploadPartURLs(ctx, objectKey, platformUploadID, int(req.TotalChunks))
			if urlErr != nil {
				c.JSON(consts.StatusInternalServerError, map[string]interface{}{
					"code":    500,
					"message": "生成预签名 URL 失败: " + urlErr.Error(),
				})
				return
			}
			respData["presigned_urls"] = presignedURLs
		}
		// sign_proxy 模式：不需要批量生成，前端每片单独请求签名
	}

	c.JSON(consts.StatusOK, map[string]interface{}{
		"code":    200,
		"message": "初始化成功",
		"data":    respData,
	})
}

// ChunkUpload .
// @router /chunk/upload/chunk/:upload_id/:chunk_index [POST]
func ChunkUpload(ctx context.Context, c *app.RequestContext) {
	var err error

	// 获取路径参数
	uploadID := c.Param("upload_id")
	chunkIndexStr := c.Param("chunk_index")

	if uploadID == "" {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "上传ID不能为空",
		})
		return
	}

	chunkIndex, err := strconv.Atoi(chunkIndexStr)
	if err != nil {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "分片索引格式错误",
		})
		return
	}

	// 检查是否为直传模式（通过 JSON body 提交 ETag，而非 multipart 文件）
	etag := string(c.FormValue("etag"))
	if etag != "" {
		// 直传模式：客户端已直接上传到存储后端，这里只记录 ETag
		uploadReq := &chunkService.UploadChunkReq{
			UploadID:   uploadID,
			ChunkIndex: chunkIndex,
			ChunkHash:  etag,
			ChunkSize:  0, // 直传模式下服务端不知道分片大小
		}

		result, uploadErr := getChunkService().UploadChunk(ctx, uploadReq)
		if uploadErr != nil {
			c.JSON(consts.StatusInternalServerError, map[string]interface{}{
				"code":    500,
				"message": "记录分片信息失败: " + uploadErr.Error(),
			})
			return
		}

		c.JSON(consts.StatusOK, map[string]interface{}{
			"code":    200,
			"message": "分片上报成功",
			"data": map[string]interface{}{
				"chunk_index": result.ChunkIndex,
				"chunk_hash":  result.ChunkHash,
			},
		})
		return
	}

	// 本地模式：接收文件数据
	file, err := c.FormFile("chunk")
	if err != nil {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "请上传分片文件或提供 etag",
		})
		return
	}

	// 读取文件内容
	src, err := file.Open()
	if err != nil {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": "读取文件失败: " + err.Error(),
		})
		return
	}
	defer src.Close()

	// 读取文件数据到内存
	data := make([]byte, file.Size)
	_, err = io.ReadFull(src, data)
	if err != nil && err != io.EOF && err != io.ErrUnexpectedEOF {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": "读取文件内容失败: " + err.Error(),
		})
		return
	}

	// 计算分片哈希
	hash := md5.Sum(data)
	chunkHash := hex.EncodeToString(hash[:])

	// 保存分片到存储
	err = getStorageService().SaveChunk(ctx, uploadID, chunkIndex, data)
	if err != nil {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": "保存分片失败: " + err.Error(),
		})
		return
	}

	// 记录分片上传信息
	uploadReq := &chunkService.UploadChunkReq{
		UploadID:   uploadID,
		ChunkIndex: chunkIndex,
		ChunkHash:  chunkHash,
		ChunkSize:  int(file.Size),
	}

	result, err := getChunkService().UploadChunk(ctx, uploadReq)
	if err != nil {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": "记录分片信息失败: " + err.Error(),
		})
		return
	}

	resp := &chunkmodel.ChunkUploadResp{
		Code:    200,
		Message: "分片上传成功",
		Data: &chunkmodel.ChunkUploadData{
			ChunkIndex: int32(result.ChunkIndex),
			ChunkHash:  result.ChunkHash,
		},
	}

	c.JSON(consts.StatusOK, resp)
}

// ChunkUploadStatus .
// @router /chunk/upload/status/:upload_id [GET]
func ChunkUploadStatus(ctx context.Context, c *app.RequestContext) {
	var err error

	// 获取上传ID
	uploadID := c.Param("upload_id")
	if uploadID == "" {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "上传ID不能为空",
		})
		return
	}

	// 获取上传信息
	info, err := getChunkService().GetUploadInfo(ctx, uploadID)
	if err != nil {
		c.JSON(consts.StatusNotFound, map[string]interface{}{
			"code":    404,
			"message": "上传记录不存在",
		})
		return
	}

	// 获取已上传分片索引
	uploadedIndexes, err := getChunkService().GetUploadedChunkIndexes(ctx, uploadID)
	if err != nil {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": "获取上传进度失败: " + err.Error(),
		})
		return
	}

	// 计算进度
	var progress float64
	if info.TotalChunks > 0 {
		progress = float64(len(uploadedIndexes)) / float64(info.TotalChunks) * 100
	}

	// 确定状态
	status := "uploading"
	if len(uploadedIndexes) == info.TotalChunks {
		status = "completed"
	} else if len(uploadedIndexes) == 0 {
		status = "pending"
	}

	// 转换索引数组
	uploadedIndexes32 := make([]int32, len(uploadedIndexes))
	for i, idx := range uploadedIndexes {
		uploadedIndexes32[i] = int32(idx)
	}

	resp := &chunkmodel.ChunkUploadStatusResp{
		Code:    200,
		Message: "获取成功",
		Data: &chunkmodel.ChunkUploadStatusData{
			UploadId:        info.UploadID,
			TotalChunks:     int32(info.TotalChunks),
			UploadedChunks:  int32(len(uploadedIndexes)),
			UploadedIndexes: uploadedIndexes32,
			Progress:        int32(progress),
			Status:          status,
		},
	}

	c.JSON(consts.StatusOK, resp)
}

// ChunkUploadComplete .
// @router /chunk/upload/complete/:upload_id [POST]
func ChunkUploadComplete(ctx context.Context, c *app.RequestContext) {
	var err error

	// 获取上传ID
	uploadID := c.Param("upload_id")
	if uploadID == "" {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "上传ID不能为空",
		})
		return
	}

	// 解析请求参数
	var req chunkmodel.ChunkUploadCompleteReq
	err = c.BindAndValidate(&req)
	if err != nil {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": err.Error(),
		})
		return
	}

	// 获取上传信息
	info, err := getChunkService().GetUploadInfo(ctx, uploadID)
	if err != nil {
		c.JSON(consts.StatusNotFound, map[string]interface{}{
			"code":    404,
			"message": "上传记录不存在",
		})
		return
	}

	// 检查所有分片是否已上传
	uploadedIndexes, err := getChunkService().GetUploadedChunkIndexes(ctx, uploadID)
	if err != nil {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": "检查上传状态失败: " + err.Error(),
		})
		return
	}

	if len(uploadedIndexes) < info.TotalChunks {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": fmt.Sprintf("还有 %d 个分片未上传", info.TotalChunks-len(uploadedIndexes)),
		})
		return
	}

	// 生成文件存储路径
	now := time.Now()
	fileExt := filepath.Ext(info.FileName)
	uuidFileName := uuid.New().String() + fileExt

	relativePath := filepath.Join(
		"uploads",
		now.Format("2006"),
		now.Format("01"),
		now.Format("02"),
		uuidFileName,
	)

	// 检查是否为直传模式
	storageService := getStorageService()
	platformUploadID := string(c.FormValue("platform_upload_id"))
	objectKey := string(c.FormValue("object_key"))

	if platformUploadID != "" && objectKey != "" {
		// 直传模式：调用存储后端的 CompleteMultipartUpload
		if directUploader, ok := storageService.(storage.DirectUploader); ok {
			// 收集已完成分片的 ETag
			var parts []storage.CompletedPart
			for i := 0; i < info.TotalChunks; i++ {
				// 从 chunk service 获取每个分片的 hash（即 ETag）
				chunkInfo, chunkErr := getChunkService().GetChunkInfo(ctx, uploadID, i)
				if chunkErr != nil {
					c.JSON(consts.StatusInternalServerError, map[string]interface{}{
						"code":    500,
						"message": fmt.Sprintf("获取分片 %d 信息失败: %v", i, chunkErr),
					})
					return
				}
				parts = append(parts, storage.CompletedPart{
					PartNumber: i + 1, // S3 part number 从 1 开始
					ETag:       chunkInfo.ChunkHash,
				})
			}

			err = directUploader.CompleteMultipartUpload(ctx, objectKey, platformUploadID, parts)
			if err != nil {
				c.JSON(consts.StatusInternalServerError, map[string]interface{}{
					"code":    500,
					"message": "完成直传分片合并失败: " + err.Error(),
				})
				return
			}
			// 直传模式使用 objectKey 作为 relativePath
			relativePath = objectKey
		}
	} else {
		// 本地/服务端模式：合并分片
		err = storageService.MergeChunks(ctx, uploadID, info.TotalChunks, relativePath)
		if err != nil {
			c.JSON(consts.StatusInternalServerError, map[string]interface{}{
				"code":    500,
				"message": "合并分片失败: " + err.Error(),
			})
			return
		}
	}

	// 计算过期时间
	expireTime := utils.CalculateExpireTime(int(req.ExpireValue), req.ExpireStyle)
	expireCount := utils.CalculateExpireCount(req.ExpireStyle, int(req.ExpireValue))

	// 获取用户ID（如果有）
	var userID *uint
	if uid, exists := c.Get("user_id"); exists {
		if uidUint, ok := uid.(uint); ok {
			userID = &uidUint
		}
	}

	// 获取客户端 IP
	ownerIP := c.ClientIP()

	// 确定上传类型
	uploadType := "anonymous"
	if userID != nil {
		uploadType = "authenticated"
	}

	// 创建分享记录
	shareReq := &shareService.ShareFileReq{
		FilePath:     filepath.Dir(relativePath),
		FileName:     info.FileName,
		StoredName:   filepath.Base(relativePath),
		Size:         info.FileSize,
		ExpiredAt:    expireTime,
		ExpiredCount: expireCount,
		RequireAuth:  req.RequireAuth,
		UserID:       userID,
		UploadType:   uploadType,
		OwnerIP:      ownerIP,
		FileHash:     uploadID,
		IsChunked:    true,
		UploadID:     uploadID,
	}

	shareResult, err := getShareService().ShareFile(ctx, shareReq)
	if err != nil {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": "创建分享记录失败: " + err.Error(),
		})
		return
	}

	// 更新上传状态为完成
	err = getChunkService().CompleteUpload(ctx, uploadID)
	if err != nil {
		// 记录错误但不影响返回结果
		fmt.Printf("更新上传状态失败: %v\n", err)
	}

	// 生成分享URL
	fullShareURL := httpurl.BuildPublicShareURL(c, shareResult.Code)

	resp := &chunkmodel.ChunkUploadCompleteResp{
		Code:    200,
		Message: "上传完成",
		Data: &chunkmodel.ChunkUploadCompleteData{
			ShareCode: shareResult.Code,
			ShareUrl:  fullShareURL,
			FileName:  info.FileName,
			FileSize:  info.FileSize,
		},
	}

	c.JSON(consts.StatusOK, resp)
}

// ChunkUploadCancel .
// @router /chunk/upload/cancel/:upload_id [DELETE]
func ChunkUploadCancel(ctx context.Context, c *app.RequestContext) {
	// 获取上传ID
	uploadID := c.Param("upload_id")
	if uploadID == "" {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "上传ID不能为空",
		})
		return
	}

	// 检查是否为直传模式
	storageService := getStorageService()
	platformUploadID := string(c.FormValue("platform_upload_id"))
	objectKey := string(c.FormValue("object_key"))

	if platformUploadID != "" && objectKey != "" {
		// 直传模式：取消平台侧分片上传
		if directUploader, ok := storageService.(storage.DirectUploader); ok {
			if abortErr := directUploader.AbortMultipartUpload(ctx, objectKey, platformUploadID); abortErr != nil {
				fmt.Printf("取消直传分片失败: %v\n", abortErr)
			}
		}
	} else {
		// 本地模式：删除分片存储
		if cleanErr := storageService.CleanChunks(ctx, uploadID); cleanErr != nil {
			fmt.Printf("清理分片文件失败: %v\n", cleanErr)
		}
	}

	// 删除上传记录
	err := getChunkService().DeleteUpload(ctx, uploadID)
	if err != nil {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": "取消上传失败: " + err.Error(),
		})
		return
	}

	resp := &chunkmodel.ChunkUploadCancelResp{
		Code:    200,
		Message: "上传已取消",
	}

	c.JSON(consts.StatusOK, resp)
}

// ChunkUploadSign 签名代理接口（sign_proxy 模式专用，又拍云等）
// @router /chunk/upload/sign/:upload_id/:chunk_index [POST]
func ChunkUploadSign(ctx context.Context, c *app.RequestContext) {
	uploadID := c.Param("upload_id")
	chunkIndexStr := c.Param("chunk_index")

	if uploadID == "" {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "上传ID不能为空",
		})
		return
	}

	chunkIndex, err := strconv.Atoi(chunkIndexStr)
	if err != nil {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "分片索引格式错误",
		})
		return
	}

	// 从请求中获取平台参数
	platformUploadID := string(c.FormValue("platform_upload_id"))
	objectKey := string(c.FormValue("object_key"))
	totalChunksStr := string(c.FormValue("total_chunks"))

	if platformUploadID == "" || objectKey == "" {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "platform_upload_id 和 object_key 不能为空",
		})
		return
	}

	totalChunks, _ := strconv.Atoi(totalChunksStr)
	if totalChunks <= 0 {
		totalChunks = 1
	}

	// 获取存储服务并生成签名
	storageService := getStorageService()
	directUploader, ok := storageService.(storage.DirectUploader)
	if !ok || !directUploader.SupportsDirectUpload() {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "当前存储不支持直传",
		})
		return
	}

	authInfo, err := directUploader.GenerateUploadPartAuth(ctx, objectKey, platformUploadID, chunkIndex, totalChunks)
	if err != nil {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": "生成分片签名失败: " + err.Error(),
		})
		return
	}

	c.JSON(consts.StatusOK, map[string]interface{}{
		"code":    200,
		"message": "签名生成成功",
		"data":    authInfo,
	})
}
